import Constants from 'expo-constants';
import * as SecureStore from 'expo-secure-store';
import type { StaffProfile, ProfileUpdateRequest } from '../types/api.types';

const API_URL = Constants.expoConfig?.extra?.apiUrl || 'http://localhost:3001/api';

interface DashboardData {
  teacher: {
    id: string;
    name: string;
    code: string;
    role: string;
    photo?: string;
  };
  classTeacher: {
    id: string;
    name: string;
    section: string;
  } | null;
  attendance: {
    date: string;
    status: string | null;
    inTime: string | null;
    outTime: string | null;
  };
  timetable: Array<{
    periodIndex: number;
    classId: {
      name: string;
      section: string;
    };
    subject: string;
    room: string;
  }>;
  substitutions: Array<{
    id: string;
    date: string;
    classId: {
      name: string;
      section: string;
    };
    period: string;
    absentTeacherId: {
      name: string;
    };
  }>;
  gatePasses: Array<{
    id: string;
    studentId: {
      name: string;
      rollNo: number;
    };
    date: string;
    reason: string;
  }>;
  appointments: Array<{
    id: string;
    visitorName: string;
    purpose: string;
    fromDateTime: string;
  }>;
  unreadAnnouncements: number;
}

class APIService {
  private token: string | null = null;

  async getToken() {
    if (!this.token) {
      try {
        this.token = await SecureStore.getItemAsync('user_token');
      } catch (error) {
        // If decryption fails, clear corrupted data
        if (error?.message?.includes('Could not decrypt')) {
          console.log('Clearing corrupted token...');
          await SecureStore.deleteItemAsync('user_token').catch(() => {});
          this.token = null;
        }
      }
    }
    return this.token;
  }

  async getHeaders() {
    const token = await this.getToken();
    return {
      'Content-Type': 'application/json',
      ...(token && { Authorization: `Bearer ${token}` }),
    };
  }

  private async fetchWithTimeout(url: string, options: RequestInit = {}, timeoutMs = 10000): Promise<Response> {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), timeoutMs);
    try {
      const response = await fetch(url, {
        ...options,
        signal: controller.signal,
      });
      clearTimeout(timeoutId);
      return response;
    } catch (error) {
      clearTimeout(timeoutId);
      throw error;
    }
  }

  async getDashboardData(teacherId: string): Promise<DashboardData> {
    const response = await this.fetchWithTimeout(
      `${API_URL}/mobile/teacher/${teacherId}/dashboard`,
      { headers: await this.getHeaders() },
      30000 // Increase timeout to 30 seconds for dashboard
    );
    if (!response.ok) throw new Error('Failed to fetch dashboard data');
    return response.json();
  }

  async getTimetable(teacherId: string) {
    const response = await this.fetchWithTimeout(
      `${API_URL}/mobile/teacher/${teacherId}/timetable`,
      { headers: await this.getHeaders() }
    );
    if (!response.ok) throw new Error('Failed to fetch timetable');
    return response.json();
  }

  async markTeacherAttendance(teacherId: string, data: { status: string; inTime?: string; outTime?: string }) {
    const response = await this.fetchWithTimeout(
      `${API_URL}/mobile/teacher/${teacherId}/attendance`,
      {
        method: 'POST',
        headers: await this.getHeaders(),
        body: JSON.stringify(data),
      }
    );
    if (!response.ok) throw new Error('Failed to mark attendance');
    return response.json();
  }

  async resetTeacherAttendance(teacherId: string) {
    const response = await this.fetchWithTimeout(
      `${API_URL}/mobile/teacher/${teacherId}/attendance`,
      {
        method: 'DELETE',
        headers: await this.getHeaders(),
      }
    );
    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(errorData.error || 'Failed to reset attendance');
    }
    return response.json();
  }

  async getClassStudents(teacherId: string) {
    const response = await this.fetchWithTimeout(
      `${API_URL}/mobile/teacher/${teacherId}/class-students`,
      { headers: await this.getHeaders() }
    );
    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(errorData.error || `Failed to fetch class students (${response.status})`);
    }
    return response.json();
  }

  async getClassAttendance(teacherId: string, date: string) {
    const response = await this.fetchWithTimeout(
      `${API_URL}/mobile/teacher/${teacherId}/class-attendance/${date}`,
      { headers: await this.getHeaders() }
    );
    if (!response.ok) throw new Error('Failed to fetch class attendance');
    return response.json();
  }

