import Constants from 'expo-constants';
import * as SecureStore from 'expo-secure-store';
import {
  ChatPermissions,
  Conversation,
  Message,
  UserPresence,
  FileUploadResponse,
} from '../types/api.types';

const API_URL = Constants.expoConfig?.extra?.apiUrl || 'http://localhost:3001/api';

class ChatService {
  private async getHeaders() {
    try {
      const token = await SecureStore.getItemAsync('user_token');
      return {
        'Content-Type': 'application/json',
        ...(token && { Authorization: `Bearer ${token}` }),
      };
    } catch (error) {
      // If decryption fails, return headers without token
      if (error?.message?.includes('Could not decrypt')) {
        console.log('Clearing corrupted token in chat service...');
        await SecureStore.deleteItemAsync('user_token').catch(() => {});
      }
      return {
        'Content-Type': 'application/json',
      };
    }
  }

  private async getAuthHeaders() {
    try {
      const token = await SecureStore.getItemAsync('user_token');
      const headers: Record<string, string> = {};

      if (token) {
        headers['Authorization'] = `Bearer ${token}`;
      }

      return headers;
    } catch (error) {
      // If decryption fails, return empty headers
      if (error?.message?.includes('Could not decrypt')) {
        console.log('Clearing corrupted token in chat service...');
        await SecureStore.deleteItemAsync('user_token').catch(() => {});
      }
      return {};
    }
  }

  // Get user's chat permissions
  async getPermissions(userId: string, userType: 'staff' | 'student'): Promise<ChatPermissions> {
    try {
      const response = await fetch(
        `${API_URL}/messages/permissions?userId=${userId}&userType=${userType}`,
        {
          headers: await this.getHeaders(),
        }
      );

      if (!response.ok) {
        throw new Error('Failed to get permissions');
      }

      return await response.json();
    } catch (error) {
      console.error('Error getting permissions:', error);
      throw error;
    }
  }

  // Get all conversations for a user
  async getConversations(
    userId: string,
    userType: 'staff' | 'student'
  ): Promise<Conversation[]> {
    try {
      const headers = await this.getHeaders();
      console.log('📡 [CHAT] Fetching conversations:', {
        url: `${API_URL}/messages/conversations?userId=${userId}&userType=${userType}`,
        hasAuth: !!headers.Authorization,
        authPrefix: headers.Authorization?.substring(0, 20) + '...',
      });

      const response = await fetch(
        `${API_URL}/messages/conversations?userId=${userId}&userType=${userType}`,
        {
          headers,
        }
      );

      console.log('📡 [CHAT] Response status:', response.status, response.statusText);

      if (!response.ok) {
        const errorData = await response.json().catch(() => ({ error: 'Unknown error' }));
        console.error('❌ [CHAT] Error response:', errorData);
        throw new Error(errorData.error || errorData.message || `Failed to get conversations (${response.status})`);
      }

      const data = await response.json();
      console.log('✅ [CHAT] Conversations loaded:', data.length);
      // Convert date strings to Date objects
      return data.map((conv: any) => ({
        ...conv,
        lastMessage: conv.lastMessage
          ? {
              ...conv.lastMessage,
              timestamp: new Date(conv.lastMessage.timestamp),
            }
          : undefined,
        updatedAt: new Date(conv.updatedAt),
      }));
    } catch (error: any) {
      console.error('❌ [CHAT] Error getting conversations:', error.message);
      console.error('❌ [CHAT] Full error:', error);
      return [];
    }
  }

  // Create or get a conversation
  async createConversation(
    user1Id: string,
    user1Type: 'staff' | 'student',
    user2Id: string,
    user2Type: 'staff' | 'student'
  ): Promise<Conversation> {
    try {
      const response = await fetch(`${API_URL}/messages/conversations`, {
        method: 'POST',
        headers: await this.getHeaders(),
        body: JSON.stringify({
          user1Id,
          user1Type,
          user2Id,
          user2Type,
        }),
      });

      if (!response.ok) {
        const error = await response.json();
        throw new Error(error.message || 'Failed to create conversation');
      }

      const data = await response.json();
      return {
        ...data,
        updatedAt: new Date(data.updatedAt),
        createdAt: new Date(data.createdAt),
      };
    } catch (error) {
      console.error('Error creating conversation:', error);
      throw error;
    }
  }

  // Get messages for a conversation
  async getMessages(
    conversationId: string,
    limit: number = 50,
    before: Date | null = null
  ): Promise<Message[]> {
    try {
      let url = `${API_URL}/messages/conversations/${conversationId}/messages?limit=${limit}`;
      if (before) {
        url += `&before=${before.toISOString()}`;
      }

      const response = await fetch(url, {
        headers: await this.getHeaders(),
      });

      if (!response.ok) {
        throw new Error('Failed to get messages');
      }

      const data = await response.json();
      // Convert date strings to Date objects
      return data.map((msg: any) => ({
        ...msg,
        createdAt: new Date(msg.createdAt),
        readAt: msg.readAt ? new Date(msg.readAt) : undefined,
      }));
    } catch (error) {
      console.error('Error getting messages:', error);
      return [];
    }
  }

  // Send a message (REST fallback)
  async sendMessage(data: {
    conversationId: string;
    senderId: string;
    senderModel: 'Staff' | 'Student';
    receiverId: string;
    receiverModel: 'Staff' | 'Student';
    content: string;
    type?: 'text' | 'image' | 'file' | 'audio' | 'video';
    fileUrl?: string;
    fileName?: string;
    fileSize?: number;
    replyTo?: string | { messageId: string };
    forwardedFrom?: any;
  }): Promise<Message> {
    try {
      const response = await fetch(`${API_URL}/messages`, {
        method: 'POST',
        headers: await this.getHeaders(),
        body: JSON.stringify(data),
      });

      if (!response.ok) {
        throw new Error('Failed to send message');
      }

      const msg = await response.json();
      return {
        ...msg,
        createdAt: new Date(msg.createdAt),
        readAt: msg.readAt ? new Date(msg.readAt) : undefined,
      };
    } catch (error) {
      console.error('Error sending message:', error);
      throw error;
    }
  }

  // Mark messages as read
  async markAsRead(conversationId: string, userId: string): Promise<{ success: boolean }> {
    try {
      const response = await fetch(`${API_URL}/messages/read`, {
        method: 'PUT',
        headers: await this.getHeaders(),
        body: JSON.stringify({ conversationId, userId }),
      });

      if (!response.ok) {
        throw new Error('Failed to mark as read');
      }

      return await response.json();
    } catch (error) {
      console.error('Error marking as read:', error);
      throw error;
    }
  }

  // Delete a message
  async deleteMessage(messageId: string, userId: string): Promise<{ success: boolean }> {
    try {
      const response = await fetch(
        `${API_URL}/messages/${messageId}?userId=${userId}`,
        {
          method: 'DELETE',
          headers: await this.getHeaders(),
        }
      );

      if (!response.ok) {
        throw new Error('Failed to delete message');
      }

      return await response.json();
    } catch (error) {
      console.error('Error deleting message:', error);
      throw error;
    }
  }

  // Search messages
  async searchMessages(userId: string, query: string, limit: number = 20): Promise<Message[]> {
    try {
      const response = await fetch(
        `${API_URL}/messages/search?userId=${userId}&query=${encodeURIComponent(
          query
        )}&limit=${limit}`,
        {
          headers: await this.getHeaders(),
        }
      );

      if (!response.ok) {
        throw new Error('Failed to search messages');
      }

      const data = await response.json();
      return data.map((msg: any) => ({
        ...msg,
        createdAt: new Date(msg.createdAt),
        readAt: msg.readAt ? new Date(msg.readAt) : undefined,
      }));
    } catch (error) {
      console.error('Error searching messages:', error);
      return [];
    }
  }

  // Get user presence
  async getUserPresence(userId: string): Promise<UserPresence> {
    try {
      const response = await fetch(`${API_URL}/messages/presence/${userId}`, {
        headers: await this.getHeaders(),
      });

      if (!response.ok) {
        throw new Error('Failed to get presence');
      }

      const data = await response.json();
      return {
        ...data,
        lastSeen: data.lastSeen ? new Date(data.lastSeen) : undefined,
      };
    } catch (error) {
      console.error('Error getting presence:', error);
      return { userId, status: 'offline', lastSeen: undefined };
    }
  }

  // Get online users
  async getOnlineUsers(): Promise<UserPresence[]> {
    try {
      const response = await fetch(`${API_URL}/messages/presence/online`, {
        headers: await this.getHeaders(),
      });

      if (!response.ok) {
        throw new Error('Failed to get online users');
      }

      const data = await response.json();
      return data.map((user: any) => ({
        ...user,
        lastSeen: user.lastSeen ? new Date(user.lastSeen) : undefined,
      }));
    } catch (error) {
      console.error('Error getting online users:', error);
      return [];
    }
  }

  // Upload file for chat
  async uploadFile(file: {
    uri: string;
    name: string;
    type: string;
    size?: number;
  }): Promise<FileUploadResponse> {
    try {
      const formData = new FormData();

      // React Native requires different format for FormData
      formData.append('file', {
        uri: file.uri,
        name: file.name,
        type: file.type,
      } as any);

      const headers = await this.getAuthHeaders();

      const response = await fetch(`${API_URL}/upload`, {
        method: 'POST',
        headers,
        body: formData,
      });

      if (!response.ok) {
        const errorData = await response.json().catch(() => ({}));
        throw new Error(errorData.error || 'Failed to upload file');
      }

      return await response.json();
    } catch (error) {
      console.error('Error uploading file:', error);
      throw error;
    }
  }

  // Edit message
  async editMessage(
    messageId: string,
    content: string,
    userId: string
  ): Promise<Message> {
    try {
      const response = await fetch(`${API_URL}/messages/${messageId}/edit`, {
        method: 'PUT',
        headers: await this.getHeaders(),
        body: JSON.stringify({ content, userId }),
      });

      if (!response.ok) {
        throw new Error('Failed to edit message');
      }

      return await response.json();
    } catch (error) {
      console.error('Error editing message:', error);
      throw error;
    }
  }

  // React to message
  async reactToMessage(
    messageId: string,
    emoji: string,
    userId: string,
    userModel: 'Staff' | 'Student'
  ): Promise<{ reactions: any[] }> {
    try {
      const response = await fetch(`${API_URL}/messages/${messageId}/react`, {
        method: 'POST',
        headers: await this.getHeaders(),
        body: JSON.stringify({ emoji, userId, userModel }),
      });

      if (!response.ok) {
        throw new Error('Failed to react to message');
      }

      return await response.json();
    } catch (error) {
      console.error('Error reacting to message:', error);
      throw error;
    }
  }

  // Pin/unpin message
  async pinMessage(messageId: string, userId: string, pinned: boolean): Promise<{ pinned: boolean }> {
    try {
      const response = await fetch(`${API_URL}/messages/${messageId}/pin`, {
        method: 'POST',
        headers: await this.getHeaders(),
        body: JSON.stringify({ userId, pinned }),
      });

      if (!response.ok) {
        throw new Error('Failed to pin message');
      }

      return await response.json();
    } catch (error) {
      console.error('Error pinning message:', error);
      throw error;
    }
  }

  // Pin/unpin conversation
  async pinConversation(
    conversationId: string,
    userId: string,
    pinned: boolean
  ): Promise<{ pinned: boolean }> {
    try {
      const response = await fetch(`${API_URL}/messages/conversations/${conversationId}/pin`, {
        method: 'POST',
        headers: await this.getHeaders(),
        body: JSON.stringify({ userId, pinned }),
      });

      if (!response.ok) {
        throw new Error('Failed to pin conversation');
      }

      return await response.json();
    } catch (error) {
      console.error('Error pinning conversation:', error);
      throw error;
    }
  }

  // Mute/unmute conversation
  async muteConversation(
    conversationId: string,
    userId: string,
    muted: boolean,
    mutedUntil?: Date
  ): Promise<{ muted: boolean }> {
    try {
      const response = await fetch(`${API_URL}/messages/conversations/${conversationId}/mute`, {
        method: 'POST',
        headers: await this.getHeaders(),
        body: JSON.stringify({
          userId,
          muted,
          mutedUntil: mutedUntil ? mutedUntil.toISOString() : undefined,
        }),
      });

      if (!response.ok) {
        throw new Error('Failed to mute conversation');
      }

      return await response.json();
    } catch (error) {
      console.error('Error muting conversation:', error);
      throw error;
    }
  }

  // Delete conversation
  async deleteConversation(conversationId: string, userId: string): Promise<{ success: boolean }> {
    try {
      const response = await fetch(`${API_URL}/messages/conversations/${conversationId}`, {
        method: 'DELETE',
        headers: await this.getHeaders(),
        body: JSON.stringify({ userId }),
      });

      if (!response.ok) {
        throw new Error('Failed to delete conversation');
      }

      return await response.json();
    } catch (error) {
      console.error('Error deleting conversation:', error);
      throw error;
    }
  }

  // Get available contacts (staff and students)
  async getContacts(userType: 'staff' | 'student' = 'staff'): Promise<{
    staff: Array<{
      id: string;
      name: string;
      role?: string;
      avatar?: string;
    }>;
    students: Array<{
      id: string;
      name: string;
      rollNo?: number;
      avatar?: string;
    }>;
  }> {
    try {
      const response = await fetch(`${API_URL}/messages/contacts?userType=${userType}`, {
        headers: await this.getHeaders(),
      });

      if (!response.ok) {
        throw new Error('Failed to get contacts');
      }

      const data = await response.json();
      return data;
    } catch (error) {
      console.error('Error getting contacts:', error);
      return { staff: [], students: [] };
    }
  }
}

export default new ChatService();

