     1→import React, { createContext, useState, useContext, useEffect } from 'react';
     2→import * as SecureStore from 'expo-secure-store';
     3→import { router } from 'expo-router';
     4→
     5→interface User {
     6→  id: string;
     7→  code: string;
     8→  name: string;
     9→  role: string;
    10→  email: string;
    11→  phone: string;
    12→  classes: Array<{ id: string; name: string; section: string }>;
    13→  token: string;
    14→  employeeId?: string;
    15→}
    16→
    17→interface AuthContextType {
    18→  user: User | null;
    19→  isAuthenticated: boolean;
    20→  isLoading: boolean;
    21→  isFirstLogin: boolean;
    22→  login: (userData: User) => Promise<void>;
    23→  logout: () => Promise<void>;
    24→  completeFirstLogin: () => Promise<void>;
    25→}
    26→
    27→const AuthContext = createContext<AuthContextType | undefined>(undefined);
    28→
    29→const TOKEN_KEY = 'user_token';
    30→const USER_KEY = 'user_data';
    31→const FIRST_LOGIN_KEY = 'first_login_completed';
    32→
    33→export function AuthProvider({ children }: { children: React.ReactNode }) {
    34→  const [user, setUser] = useState<User | null>(null);
    35→  const [isLoading, setIsLoading] = useState(true);
    36→  const [isFirstLogin, setIsFirstLogin] = useState(false);
    37→
    38→  useEffect(() => {
    39→    loadStoredData();
    40→  }, []);
    41→
    42→  const loadStoredData = async () => {
    43→    try {
    44→      const [token, userData] = await Promise.all([
    45→        SecureStore.getItemAsync(TOKEN_KEY),
    46→        SecureStore.getItemAsync(USER_KEY),
    47→      ]);
    48→
    49→      if (token && userData) {
    50→        setUser(JSON.parse(userData));
    51→        // Check if user has completed first login
    52→        const firstLoginCompleted = await SecureStore.getItemAsync(FIRST_LOGIN_KEY);
    53→        setIsFirstLogin(!firstLoginCompleted);
    54→      }
    55→    } catch (error) {
    56→      console.error('Error loading stored data:', error);
    57→      // If decryption fails, clear corrupted data
    58→      if (error?.message?.includes('Could not decrypt')) {
    59→        console.log('Clearing corrupted SecureStore data...');
    60→        try {
    61→          await Promise.all([
    62→            SecureStore.deleteItemAsync(TOKEN_KEY).catch(() => {}),
    63→            SecureStore.deleteItemAsync(USER_KEY).catch(() => {}),
    64→            SecureStore.deleteItemAsync(FIRST_LOGIN_KEY).catch(() => {}),
    65→          ]);
    66→        } catch (clearError) {
    67→          console.error('Error clearing corrupted data:', clearError);
    68→        }
    69→      }
    70→    } finally {
    71→      setIsLoading(false);
    72→    }
    73→  };
    74→
    75→  const login = async (userData: User) => {
    76→    try {
    77→      await Promise.all([
    78→        SecureStore.setItemAsync(TOKEN_KEY, userData.token),
    79→        SecureStore.setItemAsync(USER_KEY, JSON.stringify(userData)),
    80→      ]);
    81→      setUser(userData);
    82→      // Check if this is first login
    83→      const firstLoginCompleted = await SecureStore.getItemAsync(FIRST_LOGIN_KEY);
    84→      setIsFirstLogin(!firstLoginCompleted);
    85→    } catch (error) {
    86→      console.error('Error storing auth data:', error);
    87→      throw error;
    88→    }
    89→  };
    90→
    91→  const completeFirstLogin = async () => {
    92→    try {
    93→      await SecureStore.setItemAsync(FIRST_LOGIN_KEY, 'true');
    94→      setIsFirstLogin(false);
    95→    } catch (error) {
    96→      console.error('Error marking first login complete:', error);
    97→    }
    98→  };
    99→
   100→  const logout = async () => {
   101→    try {
   102→      await Promise.all([
   103→        SecureStore.deleteItemAsync(TOKEN_KEY),
   104→        SecureStore.deleteItemAsync(USER_KEY),
   105→        SecureStore.deleteItemAsync(FIRST_LOGIN_KEY),
   106→      ]);
   107→      setUser(null);
   108→      setIsFirstLogin(false);
   109→      router.replace('/login');
   110→    } catch (error) {
   111→      console.error('Error clearing auth data:', error);
   112→    }
   113→  };
   114→
   115→  return (
   116→    <AuthContext.Provider
   117→      value={{
   118→        user,
   119→        isAuthenticated: !!user,
   120→        isLoading,
   121→        isFirstLogin,
   122→        login,
   123→        logout,
   124→        completeFirstLogin,
   125→      }}
   126→    >
   127→      {children}
   128→    </AuthContext.Provider>
   129→  );
   130→}
   131→
   132→export function useAuth() {
   133→  const context = useContext(AuthContext);
   134→  if (context === undefined) {
   135→    throw new Error('useAuth must be used within an AuthProvider');
   136→  }
   137→  return context;
   138→}
