import React, { useEffect, useState, useCallback } from 'react';
import {
  View,
  Text,
  ScrollView,
  StyleSheet,
  TouchableOpacity,
  ActivityIndicator,
  RefreshControl,
  Alert,
  Platform,
} from 'react-native';
import { useRouter, Stack } from 'expo-router';
import { useAuth } from '../context/AuthContext';
import { useTheme } from '../context/ThemeContext';
import api from '../services/api';
import { format, parseISO } from 'date-fns';
import * as FileSystem from 'expo-file-system';
import * as Sharing from 'expo-sharing';

interface Payslip {
  _id: string;
  month: string;
  year: number;
  basicSalary: number;
  allowances: number;
  deductions: number;
  netSalary: number;
  paymentStatus: string;
  createdAt: string;
}

interface PayslipSummary {
  year: number;
  totalPayslips: number;
  totalEarnings: number;
  monthlyData: Array<{
    month: string;
    netSalary: number;
    status: string;
  }>;
}

export default function PayslipsScreen() {
  const { user } = useAuth();
  const { colors } = useTheme();
  const [payslips, setPayslips] = useState<Payslip[]>([]);
  const [summary, setSummary] = useState<PayslipSummary | null>(null);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [downloadingId, setDownloadingId] = useState<string | null>(null);
  const [selectedYear, setSelectedYear] = useState<number>(new Date().getFullYear());

  useEffect(() => {
    loadPayslips();
    loadSummary();
  }, [user, selectedYear]);

  const loadPayslips = useCallback(async () => {
    if (!user?.employeeId) return;
    try {
      const data = await api.getPayslips(user.employeeId, selectedYear);

      if (data.success) {
        setPayslips(data.payslips);
      }
    } catch (error) {
      console.error('Error loading payslips:', error);
      Alert.alert('Error', 'Failed to load payslips. Please try again.');
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  }, [user?.employeeId, selectedYear]);

  const loadSummary = useCallback(async () => {
    if (!user?.employeeId) return;
    try {
      const data = await api.getPayslipSummary(user.employeeId);

      if (data.success) {
        setSummary(data);
      }
    } catch (error) {
      console.error('Error loading summary:', error);
    }
  }, [user?.employeeId]);

  const onRefresh = () => {
    setRefreshing(true);
    loadPayslips();
    loadSummary();
  };

  const downloadPayslip = async (payslipId: string, month: string, year: number) => {
    setDownloadingId(payslipId);
    try {
      const blob = await api.downloadPayslip(payslipId);

      if (Platform.OS === 'web') {
        // For web, create download link
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.download = `payslip-${month}-${year}.pdf`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(url);
      } else {
        // For mobile, save and share
        const base64 = await blobToBase64(blob);
        const filename = `${FileSystem.documentDirectory}payslip-${month}-${year}.pdf`;
        await FileSystem.writeAsStringAsync(filename, base64, {
          encoding: FileSystem.EncodingType.Base64,
        });

        await Sharing.shareAsync(filename, {
          mimeType: 'application/pdf',
          dialogTitle: `Save Payslip - ${month} ${year}`,
        });
      }

      Alert.alert('Success', 'Payslip downloaded successfully');
    } catch (error) {
      console.error('Error downloading payslip:', error);
      Alert.alert('Error', 'Failed to download payslip. Please try again.');
    } finally {
      setDownloadingId(null);
    }
  };

  const blobToBase64 = (blob: Blob): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64 = (reader.result as string).split(',')[1];
        resolve(base64);
      };
      reader.onerror = reject;
      reader.readAsDataURL(blob);
    });
  };

  if (loading) {
    return (
      <View style={[styles.centerContainer, { backgroundColor: colors.backgroundGray }]}>
        <ActivityIndicator size="large" color={colors.primary} />
      </View>
    );
  }

  return (
    <>
      <Stack.Screen options={{ title: 'My Payslips', headerShown: true }} />
      <ScrollView
        style={{ flex: 1, backgroundColor: colors.backgroundGray }}
        refreshControl={
          <RefreshControl refreshing={refreshing} onRefresh={onRefresh} />
        }
      >
        {/* Summary Card */}
        {summary && (
          <View style={{
            margin: 16,
            padding: 20,
            backgroundColor: colors.primary,
            borderRadius: 12,
            shadowColor: '#000',
            shadowOffset: { width: 0, height: 2 },
            shadowOpacity: 0.1,
            shadowRadius: 4,
            elevation: 3,
          }}>
            <Text style={{ fontSize: 16, color: 'rgba(255,255,255,0.8)', marginBottom: 8 }}>
              Earnings Summary {summary.year}
            </Text>
            <Text style={{ fontSize: 28, fontWeight: 'bold', color: colors.white }}>
              Total: ₹{summary.totalEarnings.toLocaleString('en-IN')}
            </Text>
            <Text style={{ fontSize: 14, color: 'rgba(255,255,255,0.8)', marginTop: 4 }}>
              {summary.totalPayslips} payslips
            </Text>
          </View>
        )}

        {/* Payslips List */}
        <View style={{ padding: 16 }}>
          <Text style={{ fontSize: 20, fontWeight: 'bold', color: colors.text, marginBottom: 16 }}>
            Payslips
          </Text>

          {payslips.length > 0 ? (
            payslips.map((payslip) => (
              <View key={payslip._id} style={{
                padding: 16,
                marginBottom: 12,
                backgroundColor: colors.card,
                borderRadius: 12,
                shadowColor: '#000',
                shadowOffset: { width: 0, height: 2 },
                shadowOpacity: 0.1,
                shadowRadius: 4,
                elevation: 3,
              }}>
                <View style={{ flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center', marginBottom: 12 }}>
                  <Text style={{ fontSize: 18, fontWeight: 'bold', color: colors.text }}>
                    {payslip.month} {payslip.year}
                  </Text>
                  <View style={[
                    { paddingHorizontal: 12, paddingVertical: 4, borderRadius: 12 },
                    payslip.paymentStatus === 'paid' && { backgroundColor: '#D1FAE5' },
                    payslip.paymentStatus === 'pending' && { backgroundColor: '#FEF3C7' },
                  ]}>
                    <Text style={{ fontSize: 12, fontWeight: '600', color: '#065F46' }}>
                      {payslip.paymentStatus}
                    </Text>
                  </View>
                </View>

                <View style={{ marginBottom: 12 }}>
                  <View style={{ flexDirection: 'row', justifyContent: 'space-between', paddingVertical: 4 }}>
                    <Text style={{ fontSize: 14, color: colors.textSecondary }}>Basic:</Text>
                    <Text style={{ fontSize: 14, color: colors.text, fontWeight: '500' }}>
                      ₹{payslip.basicSalary.toLocaleString('en-IN')}
                    </Text>
                  </View>
                  <View style={{ flexDirection: 'row', justifyContent: 'space-between', paddingVertical: 4 }}>
                    <Text style={{ fontSize: 14, color: colors.textSecondary }}>Allowances:</Text>
                    <Text style={{ fontSize: 14, color: colors.text, fontWeight: '500' }}>
                      ₹{payslip.allowances.toLocaleString('en-IN')}
                    </Text>
                  </View>
                  <View style={{ flexDirection: 'row', justifyContent: 'space-between', paddingVertical: 4 }}>
                    <Text style={{ fontSize: 14, color: colors.textSecondary }}>Deductions:</Text>
                    <Text style={{ fontSize: 14, color: colors.text, fontWeight: '500' }}>
                      ₹{payslip.deductions.toLocaleString('en-IN')}
                    </Text>
                  </View>
                  <View style={[{ flexDirection: 'row', justifyContent: 'space-between', borderTopWidth: 1, borderTopColor: colors.border, paddingTop: 8, marginTop: 4 }]}>
                    <Text style={{ fontSize: 14, color: colors.textSecondary }}>Net Salary:</Text>
                    <Text style={{ fontSize: 16, color: colors.primary, fontWeight: 'bold' }}>
                      ₹{payslip.netSalary.toLocaleString('en-IN')}
                    </Text>
                  </View>
                </View>

                <TouchableOpacity
                  style={[
                    { backgroundColor: colors.primary, padding: 12, borderRadius: 8, alignItems: 'center' },
                    downloadingId === payslip._id && { opacity: 0.7 }
                  ]}
                  onPress={() => downloadPayslip(payslip._id, payslip.month, payslip.year)}
                  disabled={downloadingId === payslip._id}
                >
                  {downloadingId === payslip._id ? (
                    <ActivityIndicator size="small" color={colors.white} />
                  ) : (
                    <Text style={{ color: colors.white, fontSize: 14, fontWeight: '600' }}>Download PDF</Text>
                  )}
                </TouchableOpacity>
              </View>
            ))
          ) : (
            <View style={styles.centerContainer}>
              <Text style={{ fontSize: 16, color: colors.textSecondary, textAlign: 'center' }}>
                No payslips available for {selectedYear}
              </Text>
            </View>
          )}
        </View>
      </ScrollView >
    </>
  );
}

const styles = StyleSheet.create({
  centerContainer: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
  },
});
